const t=new Map;var e={tag:"ok-icon",attr:{name:{},set:{default:"lucide"}},context:e=>({async updateIcon(){const n=e.$attr.name;if(n)try{const n=`https://api.iconify.design/${e.$attr.set}/${e.$attr.name}.svg`;if(t.has(n))e.$el.innerHTML=t.get(n);else{e.$el.innerHTML='<span style="opacity:0.5">&nbsp;</span>';const a=await fetch(n);if(!a.ok)throw new Error("Icon not found");const s=await a.text();t.set(n,s),e.$el.innerHTML=s}}catch(t){if(e.$__unmount__$)return;e.$el.innerHTML=`\x3c!-- icon "${n}" not found --\x3e<span style="display:block;text-align:center">?</span>`}}}),mount(t){this.updateIcon(),t.$watch(()=>[t.$attr.name,t.$attr.set],()=>{this.updateIcon()})},style:"[tag]{display:inline-flex;width:1em;height:1em;line-height:1}[tag] svg{flex-grow:1;stroke:currentColor;fill:transparent;display:block}"};export{e as default};
